using Microsoft.AspNetCore.Mvc;
using System;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.Extensions.Primitives;

namespace WebhookProxy
{
    [ApiController]
    [Route("[controller]")]
    public class ProxyController : ControllerBase
    {
        private readonly HttpClient _httpClient;

        public ProxyController(HttpClient httpClient)
        {
            _httpClient = httpClient;
        }

        [HttpPost]
        public async Task<IActionResult> Post([FromBody] string url)
        {
            if (string.IsNullOrEmpty(url)) return BadRequest("URL is required.");

            var request = new HttpRequestMessage(new HttpMethod("POST"), url);
            using (var response = await _httpClient.SendAsync(request))
            {
                response.EnsureSuccessStatusCode();
                return Content(await response.Content.ReadAsStringAsync(), "text/plain");
            }
        }
    }
